package qa.operator;

public class Assignment_operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a=10; //initialise value
		
		a+=2;//adition
		System.out.println(a);
		
		a-=2;//substraction
		System.out.println(a);
		
		a*=2;//multiplication
		System.out.println(a);
		
		a/=2;//divition
		System.out.println(a);
		
		a%=2;//modulation
		System.out.println(a);

	}

}
